 13→/**
 14→ * Pure unit tests for TaskStatus enum.
 15→ * No Spring context needed — tests enum values and state machine logic.
 16→ */
 17→class TaskStatusTest {
 18→
 19→    // ── Contract: enum values ──────────────────────────────────────────
 20→
 21→    @Test
 22→    @DisplayName("TaskStatus has exactly 4 values: TODO, IN_PROGRESS, DONE, CLOSED")
 23→    void shouldHaveExactlyFourValues() {
 24→        TaskStatus[] values = TaskStatus.values();
 25→        assertEquals(4, values.length);
 26→        assertNotNull(TaskStatus.valueOf("TODO"));
 27→        assertNotNull(TaskStatus.valueOf("IN_PROGRESS"));
 28→        assertNotNull(TaskStatus.valueOf("DONE"));
 29→        assertNotNull(TaskStatus.valueOf("CLOSED"));
 30→    }
 31→
 32→    // ── getAllowedTransitions ───────────────────────────────────────────
 33→
 34→    @Nested
 35→    @DisplayName("getAllowedTransitions()")
 36→    class GetAllowedTransitionsTests {
 37→
 38→        @Test
 39→        @DisplayName("TODO -> [IN_PROGRESS]")
 40→        void todoAllowedTransitions() {
 41→            List<TaskStatus> allowed = TaskStatus.TODO.getAllowedTransitions();
 42→            assertEquals(1, allowed.size());
 43→            assertTrue(allowed.contains(TaskStatus.IN_PROGRESS));
 44→        }
 45→
 46→        @Test
 47→        @DisplayName("IN_PROGRESS -> [TODO, DONE]")
 48→        void inProgressAllowedTransitions() {
 49→            List<TaskStatus> allowed = TaskStatus.IN_PROGRESS.getAllowedTransitions();
 50→            assertEquals(2, allowed.size());
 51→            assertTrue(allowed.contains(TaskStatus.TODO));
 52→            assertTrue(allowed.contains(TaskStatus.DONE));
 53→        }
 54→
 55→        @Test
 56→        @DisplayName("DONE -> [CLOSED]")
 57→        void doneAllowedTransitions() {
 58→            List<TaskStatus> allowed = TaskStatus.DONE.getAllowedTransitions();
 59→            assertEquals(1, allowed.size());
 60→            assertTrue(allowed.contains(TaskStatus.CLOSED));
 61→        }
 62→
 63→        @Test
 64→        @DisplayName("CLOSED -> [] (empty, terminal state)")
 65→        void closedAllowedTransitions() {
 66→            List<TaskStatus> allowed = TaskStatus.CLOSED.getAllowedTransitions();
 67→            assertNotNull(allowed);
 68→            assertTrue(allowed.isEmpty());
 69→        }
 70→    }
 71→
 72→    // ── canTransitionTo — valid transitions ────────────────────────────
 73→
 74→    @Nested
 75→    @DisplayName("canTransitionTo() — valid transitions")
 76→    class ValidTransitionTests {
 77→
 78→        @Test
 79→        @DisplayName("TODO -> IN_PROGRESS = true")
 80→        void todoToInProgress() {
 81→            assertTrue(TaskStatus.TODO.canTransitionTo(TaskStatus.IN_PROGRESS));
 82→        }
 83→
 84→        @Test
 85→        @DisplayName("IN_PROGRESS -> TODO = true")
 86→        void inProgressToTodo() {
 87→            assertTrue(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.TODO));
 88→        }
 89→
 90→        @Test
 91→        @DisplayName("IN_PROGRESS -> DONE = true")
 92→        void inProgressToDone() {
 93→            assertTrue(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.DONE));
 94→        }
 95→
 96→        @Test
 97→        @DisplayName("DONE -> CLOSED = true")
 98→        void doneToClosed() {
 99→            assertTrue(TaskStatus.DONE.canTransitionTo(TaskStatus.CLOSED));
100→        }
101→    }
102→
103→    // ── canTransitionTo — invalid transitions ──────────────────────────
104→
105→    @Nested
106→    @DisplayName("canTransitionTo() — invalid transitions")
107→    class InvalidTransitionTests {
108→
109→        @Test
110→        @DisplayName("TODO -> DONE = false")
111→        void todoToDone() {
112→            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.DONE));
113→        }
114→
115→        @Test
116→        @DisplayName("TODO -> CLOSED = false")
117→        void todoToClosed() {
118→            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.CLOSED));
119→        }
120→
121→        @Test
122→        @DisplayName("TODO -> TODO = false (self-transition)")
123→        void todoToTodo() {
124→            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.TODO));
125→        }
126→
127→        @Test
128→        @DisplayName("DONE -> TODO = false")
129→        void doneToTodo() {
130→            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.TODO));
131→        }
132→
133→        @Test
134→        @DisplayName("DONE -> IN_PROGRESS = false")
135→        void doneToInProgress() {
136→            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.IN_PROGRESS));
137→        }
138→
139→        @Test
140→        @DisplayName("DONE -> DONE = false (self-transition)")
141→        void doneToDone() {
142→            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.DONE));
143→        }
144→
145→        @ParameterizedTest(name = "CLOSED -> {0} = false")
146→        @EnumSource(TaskStatus.class)
147→        @DisplayName("CLOSED -> anything = false (terminal state)")
148→        void closedToAnything(TaskStatus target) {
149→            assertFalse(TaskStatus.CLOSED.canTransitionTo(target));
150→        }
151→
152→        @Test
153→        @DisplayName("IN_PROGRESS -> CLOSED = false")
154→        void inProgressToClosed() {
155→            assertFalse(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.CLOSED));
156→        }
157→
158→        @Test
159→        @DisplayName("IN_PROGRESS -> IN_PROGRESS = false (self-transition)")
160→        void inProgressToInProgress() {
161→            assertFalse(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.IN_PROGRESS));
162→        }
163→    }
164→
165→    // ── Edge cases ─────────────────────────────────────────────────────
166→
167→    @Test
168→    @DisplayName("canTransitionTo with null target should not throw (return false or throw NPE)")
169→    void canTransitionToNull() {
170→        // Depending on implementation, this may throw NPE or return false.
171→        // We simply verify it does not return true.
172→        try {
173→            boolean result = TaskStatus.TODO.canTransitionTo(null);
174→            assertFalse(result);
175→        } catch (NullPointerException e) {
176→            // Also acceptable behavior
177→        }
178→    }
179→}
